import torch
import torch.nn as nn
import timm

class CIFAR100NModel(nn.Module):
    def __init__(self, num_classes=100, model_name='convnext_tiny.fb_in22k_ft_in1k', pretrained=True):
        super().__init__()
        self.backbone = timm.create_model(
            model_name,
            pretrained=pretrained,
            num_classes=num_classes
        )

    def forward(self, x):
        return self.backbone(x)
